class Solution:
    def sumOfPower(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        nums.sort()
        n = len(nums)
        prefix_sum = [0] * (n + 1)

        for i in range(n):
            prefix_sum[i + 1] = prefix_sum[i] + nums[i]

        result = 0
        for i in range(n):
            # max is nums[i], min is nums[i]
            power = (nums[i] ** 2) * nums[i]
            result = (result + power) % MOD

            # max is nums[i], min is nums[j] for j < i
            # number of subsets where nums[i] is max and nums[j] is min
            # contribution is (nums[i]^2) * nums[j] * 2^{i - j - 1}
            for j in range(i):
                contribution = (nums[i] ** 2) * nums[j] * (1 << (i - j - 1))
                result = (result + contribution) % MOD

        return result
